class Solution {
public:
	pair<int, int> solve(vector<int>& coins)
	{
		pennies_left = 0;
		nickels = 0;
		for (int i = 0; i < coins.size() / 2; i++)
			pennies_left += coins[i];
		for (int i = coins.size() / 2; i < coins.size(); i++)
			nickels += coins[i] / 5;
		return make_pair(pennies_left + nickels * 5, nickels);
	}
private:	int pennies_left, nickels;
};

